import requests
from azure.identity import DefaultAzureCredential
from datetime import datetime

def check_vs_credit_usage(subscription_id: str) -> dict:
    """
    Check month-to-date credit consumption on a Visual Studio subscription.
    Returns used, available estimate (does not directly expose the credit balance
    for MOSP — uses Cost Management query instead).
    """
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }

    url = (
        f"https://management.azure.com/subscriptions/{subscription_id}/"
        f"providers/Microsoft.CostManagement/query?api-version=2023-11-01"
    )
    body = {
        "type": "ActualCost",
        "timeframe": "MonthToDate",
        "dataSet": {
            "granularity": "None",
            "aggregation": {
                "totalCost": {"name": "Cost", "function": "Sum"}
            }
        }
    }
    resp = requests.post(url, headers=headers, json=body)
    rows = resp.json().get("properties", {}).get("rows", [])
    mtd_cost = float(rows[0][0]) if rows else 0.0
    mtd_currency = rows[0][1] if rows and len(rows[0]) > 1 else "USD"
    return {
        "subscription_id": subscription_id,
        "month_to_date_cost": mtd_cost,
        "currency": mtd_currency,
        "report_date": datetime.utcnow().strftime("%Y-%m-%d"),
    }

usage = check_vs_credit_usage("<vs-subscription-id>")
print(f"MTD cost: {usage['month_to_date_cost']:.2f} {usage['currency']}")

from datetime import datetime, timedelta

def project_exhaustion(history: list[dict]) -> dict:
    if not history:
        return {}

    # Average monthly utilization over available history
    total_util = sum(r["utilized"] for r in history)
    avg_monthly = total_util / len(history)

    # Current ending balance
    ending = history[-1]["ending_balance"]

    if avg_monthly <= 0:
        return {"months_remaining": float("inf"), "projected_date": "N/A"}

    months_left = ending / avg_monthly
    projection_date = (
        datetime.utcnow() + timedelta(days=months_left * 30)
    ).strftime("%Y-%m-%d")

    return {
        "current_balance": ending,
        "avg_monthly_burn": round(avg_monthly, 2),
        "months_remaining": round(months_left, 1),
        "projected_exhaustion_date": projection_date,
    }

projection = project_exhaustion(history)
print("Credit Exhaustion Projection:")
for k, v in projection.items():
    print(f"  {k}: {v}")
